const recs = $input.all().map(i => i.json);
if (!recs || recs.length === 0) {
  return [{ json: { skipped: true, reason: 'No mature recommendations to score' } }];
}
console.log(`[feedback] Processing ${recs.length} mature recommendations`);
return recs.map(r => {
  let data = {};
  try { data = typeof r.data === 'string' ? JSON.parse(r.data) : (r.data || {}); } catch(e) {}
  return { json: { ...r, _data: data } };
});

const rec      = $('Prepare Recommendations').first().json;
const emailRes = $('Supabase — Check Email Reply').first()?.json;
const dealRes  = $('Supabase — Check Deal Progress').first()?.json;

let outcomeScore = 50; // unknown default
let outcomeNote  = 'No measurable outcome found — using neutral score';

// Email outcome
if (emailRes?.reply_received) {
  outcomeScore = 100;
  outcomeNote  = 'Email received a reply';
} else if (emailRes && !emailRes.reply_received) {
  outcomeScore = 15;
  outcomeNote  = 'Email sent, no reply after 30 days';
}

// Deal outcome (overrides if more specific)
if (dealRes?.status) {
  const stage = (dealRes.stage || '').toLowerCase();
  if (dealRes.status === 'won' || stage.includes('closed won') || stage.includes('closedwon')) {
    outcomeScore = 100;
    outcomeNote  = 'Deal closed won';
  } else if (dealRes.status === 'lost' || stage.includes('closed lost')) {
    outcomeScore = 0;
    outcomeNote  = 'Deal closed lost';
  } else if (stage.includes('contract') || stage.includes('negotiation')) {
    outcomeScore = 75;
    outcomeNote  = 'Deal progressed to late stage';
  } else if (stage.includes('proposal') || stage.includes('demo')) {
    outcomeScore = 55;
    outcomeNote  = 'Deal at proposal/demo stage';
  }
}

const shouldStoreRAG = outcomeScore >= 70;

console.log(`[feedback] rec=${rec.id} rec_type=${rec.rec_type} score=${outcomeScore} rag=${shouldStoreRAG}`);

return [{
  json: {
    rec_id:         rec.id,
    tenant_id:      rec.tenant_id,
    agent:          rec.agent,
    rec_type:       rec.rec_type,
    rec_data:       rec._data,
    outcome_score:  outcomeScore,
    outcome_note:   outcomeNote,
    should_store_rag: shouldStoreRAG
  }
}];

// Build content string for embedding
const d = $json;
const data = d.rec_data || {};

// Build a rich semantic string that captures what worked
const parts = [
  `Type: ${d.rec_type}`,
  `Agent: ${d.agent}`,
  data.email_subject ? `Email subject: ${data.email_subject}` : '',
  data.email_body    ? `Email body snippet: ${data.email_body?.substring(0, 300)}` : '',
  data.action        ? `Recommended action: ${data.action}` : '',
  data.diagnosis     ? `Diagnosis: ${data.diagnosis}` : '',
  data.blocking_factor ? `Blocking factor: ${data.blocking_factor}` : '',
  data.deal_stage    ? `Deal stage: ${data.deal_stage}` : '',
  data.industry      ? `Industry: ${data.industry}` : '',
  `Outcome: ${d.outcome_note} (score: ${d.outcome_score})`
].filter(Boolean).join(' | ');

return [{
  json: {
    ...d,
    _embed_content: parts,
    _metadata: {
      type:          d.rec_type,
      agent:         d.agent,
      outcome_score: d.outcome_score,
      rec_id:        d.rec_id,
      subject:       data.email_subject || null,
      body:          data.email_body?.substring(0, 500) || null,
      action:        data.action || null,
      stage:         data.deal_stage || null
    }
  }
}];

const prep   = $('Prepare Content for Embedding').first().json;
const embRes = $input.first().json;

if (embRes.error) {
  console.error('[feedback] Embedding failed:', embRes.error);
  // Don't crash — skip RAG store for this one
  return [{ json: { _embedding_failed: true, rec_id: prep.rec_id } }];
}

const embedding = embRes.data?.[0]?.embedding;
if (!embedding || embedding.length !== 1536) {
  console.error('[feedback] Unexpected embedding shape');
  return [{ json: { _embedding_failed: true, rec_id: prep.rec_id } }];
}

return [{
  json: {
    rec_id:    prep.rec_id,
    tenant_id: prep.tenant_id,
    content:   prep._embed_content,
    embedding: JSON.stringify(embedding),
    metadata:  JSON.stringify(prep._metadata)
  }
}];
